# shapes.spy - Interfaces and abstract base classes
interface IShape:
    def area() -> float
    def perimeter() -> float

interface IDrawable:
    def draw() -> str

@abstract
class Shape(IShape):
    @abstract
    def describe() -> str

    @virtual
    def summary() -> str:
        return "Shape summary"

