# shapes_impl.spy - Concrete shape implementations
from shapes import IShape, Shape, IDrawable

class Circle(Shape, IDrawable):
    name: str
    radius: float

    def __init__(self, name: str, radius: float):
        self.name = name
        self.radius = radius

    @override
    def area() -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter() -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe() -> str:
        return f"Circle '{self.name}' with radius {self.radius}"

    @override
    def draw() -> str:
        return f"Drawing circle: {self.name}"

class Rectangle(Shape, IDrawable):
    name: str
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        self.name = name
        self.width = width
        self.height = height

    @override
    def area() -> float:
        return self.width * self.height

    @override
    def perimeter() -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe() -> str:
        return f"Rectangle '{self.name}' {self.width}x{self.height}"

    @override
    def draw() -> str:
        return f"Drawing rectangle: {self.name}"

