# utils.spy - Utility types
struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_from_origin() -> float:
        return (self.x * self.x + self.y * self.y) ** 0.5

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3

class ShapeValidator:
    def is_valid(self, shape) -> bool:
        return shape.area() > 0.0

class MetricsCollector:
    shapes_processed: int = 0

    def __init__(self):
        self.shapes_processed = 0

    def record_shape(self, shape) -> float:
        self.shapes_processed += 1
        return shape.area()

    def get_count(self) -> int:
        return self.shapes_processed
